import { useState, useEffect } from "react";

function EmployeeJobs() {

  const [jobs, setJobs] = useState([]);
  const [applications, setApplications] = useState([]);

  // Logged in Employee (You already store logged in user)
  const loggedUser = JSON.parse(localStorage.getItem("loggedInUser"));

  useEffect(() => {
    const jobList = JSON.parse(localStorage.getItem("internalJobs")) || [];
    const apps = JSON.parse(localStorage.getItem("applications")) || [];

    setJobs(jobList);
    setApplications(apps);
  }, []);

  const applyJob = (job) => {

    if (!loggedUser) return alert("Login Required");

    // Prevent duplicate apply
    const already = applications.some(
      a => a.jobId === job.id && a.empId === loggedUser.empId
    );

    if (already) return alert("You already applied for this job!");

    const newApplication = {
      id: Date.now(),
      jobId: job.id,
      jobTitle: job.title,
      empId: loggedUser.empId,
      employee: loggedUser.name,
      email: loggedUser.username,
      status: "Pending"
    };

    const updated = [...applications, newApplication];
    setApplications(updated);
    localStorage.setItem("applications", JSON.stringify(updated));

    alert("Job Applied Successfully");
  };

  return (
    <div style={{ marginTop: "25px" }}>
      <h2>Available Internal Job Openings</h2>

      <table className="designation-table">
        <thead>
          <tr>
            <th>S.No</th>
            <th>Job Title</th>
            <th>Department</th>
            <th>Description</th>
            <th>Action</th>
          </tr>
        </thead>

        <tbody>
          {jobs.length === 0 ? (
            <tr>
              <td colSpan="5">No Internal Jobs Posted Yet</td>
            </tr>
          ) : (
            jobs.map((job, index) => (
              <tr key={job.id}>
                <td>{index + 1}</td>
                <td>{job.title}</td>
                <td>{job.department}</td>
                <td>{job.desc}</td>

                <td>
                  <button
                    className="job-edit-btn"
                    onClick={() =>
                      alert(
                        `Job Title: ${job.title}\n\nDepartment: ${job.department}\n\nDescription: ${job.desc}`
                      )
                    }
                  >
                    View
                  </button>

                  <button
                    className="job-delete-btn"
                    onClick={() => applyJob(job)}
                  >
                    Apply
                  </button>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}

export default EmployeeJobs;
